validation_script:
#!/bin/bash
IP=$(ip -4 addr show eth0 | grep -oP '(?<=inet\s)\d+(\.\d+){3}' || true)
if [[ "$IP" == "172.16.120.10" ]]; then exit 0; else exit 1; fi

